INSERT INTO `chi_users` VALUES
(1,'Mia Carter','mia@chilove.test','2026-06-24 08:29:47',NULL,NULL),
(2,'Danielle Ruiz','danielle@chilove.test','2026-06-25 07:42:13','Danielle Ruiz covers rescue and the lives dogs lead after it, reporting the chihuahua-human bond the way a journalist would, with names, specifics, and warmth she keeps on a short leash. She has fostered more small dogs than she can strictly account for.','/assets/img/authors/danielle-ruiz.svg'),
(3,'Elena Vance','elena@chilove.test','2026-06-25 12:59:55','Elena Vance writes Cheewawa\'s health explainers, turning veterinary guidance into plain English a worried owner can actually use. She is a translator, not a clinician: she reads the research, tells you what to watch for, and sends you to your own veterinarian with better questions.','/assets/img/authors/elena-vance.svg'),
(5,'Nathan Cross','nathan@chilove.test','2026-06-26 15:14:41','Nathan Cross writes Cheewawa\'s breed and behavior features, tracing where chihuahua reputations come from and what the science actually says. He is happiest with a breed standard in one hand and a study in the other, and he has never met a dog myth he did not want to take apart.','/assets/img/authors/nathan-cross.svg'),
(7,'Vania Dunn','vania@chihuacorner.com','2026-07-03 15:09:47','Vania Dunn is Cheewawa\'s news and features writer, covering pet health, rescue, and the science of living with small dogs. She reports the way a working journalist does: sources named, claims checked, and the dog kept firmly at the center of the story.','/assets/img/authors/vania-dunn.svg'),
(8,'Tyler Brennan','tyler@chihuacorner.com','2026-07-03 18:55:56','Tyler Brennan writes Cheewawa\'s lighter side, chronicling life with small dogs from the honest, faintly defeated perspective of the person holding the leash. He is fairly sure the dog is smarter than he is and has long since stopped fighting it.','/assets/img/authors/tyler-brennan.svg'),
(9,'Jessica Caldwell','jessica@chilove.test','2026-07-16 16:37:51','Jessica Caldwell writes Cheewawa\'s training and behavior guides. She translates humane, evidence-based training principles into small, doable steps that respect the world\'s tiniest big personality.','/assets/img/authors/jessica-caldwell.svg');
